import React, { useEffect, useState } from "react";
import axios from "axios";
import { XMarkIcon } from "@heroicons/react/24/solid";

// Floating Input
const FloatingLabelInput = ({
  name,
  type = "text",
  label,
  value,
  onChange,
  required,
  disabled,
}) => (
  <div className="relative w-full">
    <input
      type={type}
      name={name}
      id={name}
      value={value}
      onChange={onChange}
      placeholder=" "
      required={required}
      disabled={disabled}
      className={`peer w-full px-4 py-3 sm:py-4 rounded-lg border text-black placeholder-transparent focus:outline-none focus:ring-2 focus:ring-blue-800 focus:border-blue-800 ${
        disabled ? "bg-gray-200 cursor-not-allowed" : "border-gray-400"
      }`}
    />
    <label
      htmlFor={name}
      className={`absolute left-4 text-gray-500 text-base transition-all
        peer-placeholder-shown:top-3.5 peer-placeholder-shown:text-base peer-placeholder-shown:text-gray-400
        peer-focus:top-1 peer-focus:text-sm peer-focus:text-blue-800
        ${value ? "top-1 text-sm text-blue-800" : ""}`}
    >
      {label} {required && <span className="text-red-500">*</span>}
    </label>
  </div>
);

export default function UserAdm() {
  const BASE_URL = "http://localhost:8086/user";

  const [users, setUsers] = useState([]);
  const [filteredUsers, setFilteredUsers] = useState([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);

  const [currentPage, setCurrentPage] = useState(1);
  const usersPerPage = 5;

  const [editingUser, setEditingUser] = useState(null);

  const role = localStorage.getItem("role"); // MUST be ADMIN

  useEffect(() => {
    fetchUsers();
  }, []);

  const fetchUsers = async () => {
    try {
      const res = await axios.get(BASE_URL);
      setUsers(res.data);
      setFilteredUsers(res.data);
      setLoading(false);
    } catch (err) {
      console.error(err);
      setLoading(false);
    }
  };

  // SEARCH
  useEffect(() => {
    const filtered = users.filter((user) =>
      (user.name || "").toLowerCase().includes(search.toLowerCase()) ||
      (user.email || "").toLowerCase().includes(search.toLowerCase()) ||
      (user.username || "").toLowerCase().includes(search.toLowerCase())
    );

    setFilteredUsers(filtered);
    setCurrentPage(1);
  }, [search, users]);

  // DELETE (ADMIN ONLY)
  const deleteUser = async (id) => {
    if (role !== "ADMIN") {
      alert("Access denied!");
      return;
    }

    try {
      await axios.delete(`${BASE_URL}/${id}`);
      fetchUsers();
    } catch (err) {
      console.error(err);
    }
  };

  // UPDATE (ADMIN ONLY)
  const updateUser = async () => {
    if (role !== "ADMIN") {
      alert("Access denied!");
      return;
    }

    try {
      await axios.put(`${BASE_URL}/${editingUser.id}`, editingUser);
      setEditingUser(null);
      fetchUsers();
    } catch (err) {
      console.error(err);
    }
  };

  // PAGINATION
  const indexOfLast = currentPage * usersPerPage;
  const indexOfFirst = indexOfLast - usersPerPage;
  const currentUsers = filteredUsers.slice(indexOfFirst, indexOfLast);
  const totalPages = Math.ceil(filteredUsers.length / usersPerPage);

  return (
    <div className="bg-gray-700 min-h-screen p-6 text-gray-100">
      <h2 className="text-3xl text-center font-bold mb-6">Active Users</h2>

      {/* SEARCH */}
      <div className="flex justify-end mb-6">
        <input
          type="text"
          placeholder="Search users..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="px-4 py-2 rounded-lg w-80 text-gray-900"
        />
      </div>

      {loading ? (
        <p>Loading...</p>
      ) : (
        <>
          {/* TABLE */}
          <table className="w-full bg-gray-800 rounded-lg overflow-hidden">
            <thead className="bg-gray-700">
              <tr>
                <th>ID</th>
                <th>Name</th>
                <th>Email</th>
                <th>Username</th>
                <th>Password</th>
                <th>Actions</th>
              </tr>
            </thead>

            <tbody>
              {currentUsers.map((user) => (
                <tr key={user.id} className="border-b border-gray-600">
                  <td>{user.id}</td>
                  <td>{user.name}</td>
                  <td>{user.email}</td>
                  <td>{user.username}</td>
                  <td>********</td>

                  <td className="flex gap-2">
                    {/* ✅ EDIT ONLY FOR NON-STUDENTS */}
                    {role === "ADMIN" && user.role !== "Student" ? (
                      <button
                        onClick={() => setEditingUser(user)}
                        className="bg-blue-700 px-3 py-1 rounded"
                      >
                        Edit
                      </button>
                    ) : null}

                    {/* DELETE ALWAYS ALLOWED FOR ADMIN */}
                    {role === "ADMIN" ? (
                      <button
                        onClick={() => deleteUser(user.id)}
                        className="bg-red-600 px-3 py-1 rounded"
                      >
                        Delete
                      </button>
                    ) : (
                      <span className="text-gray-400">No access</span>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {/* PAGINATION */}
          <div className="flex justify-center mt-4 gap-2">
            {Array.from({ length: totalPages }, (_, i) => (
              <button
                key={i}
                onClick={() => setCurrentPage(i + 1)}
                className={`px-3 py-1 rounded ${
                  currentPage === i + 1 ? "bg-blue-700" : "bg-gray-600"
                }`}
              >
                {i + 1}
              </button>
            ))}
          </div>
        </>
      )}

      {/* EDIT MODAL */}
      {editingUser && (
        <div className="fixed inset-0 flex items-center justify-center bg-black/50">
          <div className="bg-white/20 p-6 rounded-xl w-[500px] relative">

            <button
              onClick={() => setEditingUser(null)}
              className="absolute top-2 right-2"
            >
              <XMarkIcon className="w-6 h-6 text-white" />
            </button>

            <h2 className="text-white text-xl mb-4">Edit User</h2>

            <FloatingLabelInput
              name="name"
              label="Name"
              value={editingUser.name}
              disabled={role !== "ADMIN" || editingUser.role === "Student"}
              onChange={(e) =>
                setEditingUser({ ...editingUser, name: e.target.value })
              }
            />

            <FloatingLabelInput
              name="email"
              label="Email"
              value={editingUser.email}
              disabled={role !== "ADMIN" || editingUser.role === "Student"}
              onChange={(e) =>
                setEditingUser({ ...editingUser, email: e.target.value })
              }
            />

            <FloatingLabelInput
              name="username"
              label="Username"
              value={editingUser.username}
              disabled={role !== "ADMIN" || editingUser.role === "Student"}
              onChange={(e) =>
                setEditingUser({
                  ...editingUser,
                  username: e.target.value,
                })
              }
            />

            <div className="flex justify-end gap-2 mt-4">
              <button
                onClick={updateUser}
                disabled={role !== "ADMIN" || editingUser.role === "Student"}
                className="bg-blue-700 px-4 py-2 rounded disabled:opacity-50"
              >
                Save
              </button>

              <button
                onClick={() => setEditingUser(null)}
                className="bg-gray-600 px-4 py-2 rounded"
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
